function validate(args, output) {
    const s = args[0];
    const cnt = new Map();
    for (const c of s) cnt.set(c, (cnt.get(c) || 0) + 1);
    const n = s.length;
    let mx = 0;
    for (const v of cnt.values()) mx = Math.max(mx, v);
    const possible = n === 0 ? true : mx <= Math.floor((n + 1) / 2);
    if (typeof output !== 'string') return false;
    if (output === '') return !possible;
    if (!possible) return false;
    const ocnt = new Map();
    for (const c of output) ocnt.set(c, (ocnt.get(c) || 0) + 1);
    if (ocnt.size !== cnt.size) return false;
    for (const [k, v] of cnt) if (ocnt.get(k) !== v) return false;
    for (let i = 1; i < output.length; i++) {
        if (output[i] === output[i - 1]) return false;
    }
    return true;
}

