class Solution:
    def reorganizeString(self, s):
        from collections import Counter
        cnt = Counter(s)
        n = len(s)
        if n and max(cnt.values()) > (n + 1) // 2:
            return ''
        order = sorted(cnt.items(), key=lambda kv: (-kv[1], kv[0]))
        chars = []
        for ch, c in order:
            chars.extend([ch] * c)
        res = [''] * n
        idx = 0
        for ch in chars:
            res[idx] = ch
            idx += 2
            if idx >= n:
                idx = 1
        return ''.join(res)

