var reorganizeString = function(s) {
    const cnt = new Map();
    for (const ch of s) cnt.set(ch, (cnt.get(ch) || 0) + 1);
    const n = s.length;
    let mx = 0;
    for (const v of cnt.values()) mx = Math.max(mx, v);
    if (n && mx > Math.floor((n + 1) / 2)) return '';
    const order = [...cnt.entries()].sort((a, b) => b[1] !== a[1] ? b[1] - a[1] : (a[0] < b[0] ? -1 : 1));
    const chars = [];
    for (const [ch, c] of order) {
        for (let i = 0; i < c; i++) chars.push(ch);
    }
    const res = new Array(n).fill('');
    let idx = 0;
    for (const ch of chars) {
        res[idx] = ch;
        idx += 2;
        if (idx >= n) idx = 1;
    }
    return res.join('');
};
